exercise.solution_code:
#include <iostream>
#include <string>

void classify(int code) {
    std::string scope{};
    std::string duration{};
    std::string linkage{};

    if (code == 1) {
        scope = "block"; duration = "automatic"; linkage = "none";
    } else if (code == 2) {
        scope = "block"; duration = "static"; linkage = "none";
    } else if (code == 3) {
        scope = "global"; duration = "static"; linkage = "external";
    } else if (code == 4) {
        scope = "global"; duration = "static"; linkage = "internal";
    } else if (code == 5) {
        scope = "global"; duration = "static"; linkage = "internal";
    } else if (code == 6) {
        scope = "global"; duration = "static"; linkage = "external";
    }

    std::cout << "Code " << code
              << ": scope=" << scope
              << ", duration=" << duration
              << ", linkage=" << linkage << '\n';
}

int main() {
    int c1{}, c2{}, c3{};
    std::cin >> c1 >> c2 >> c3;

    classify(c1);
    classify(c2);
    classify(c3);

    return 0;
}
